```class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, List<int[]>> map = new HashMap<>();
        for (int[] pair : pairs) {
            map.computeIfAbsent(pair[0], k -> new ArrayList<>()).add(pair);
            map.computeIfAbsent(pair[1], k -> new ArrayList<>()).add(pair);
        }
        List<int[]> result = new ArrayList<>();
        int start = pairs[0][0];
        while (!map.isEmpty()) {
            List<int[]> list = map.get(start);
            result.addAll(list);
            map.remove(start);
            if (list.size() > 1) {
                start = list.get(1)[1];
            } else {
                start = list.get(0)[1];
            }
        }
        return result.toArray(new int[0][]);
    }
